// Get PR data from first input, issue data from second
const prs = $input.all()[0]?.json || [];
const issues = $input.all()[1]?.json || [];

// PRs don't have pull_request key on issues endpoint - filter correctly
const actualIssues = Array.isArray(issues) ? issues.filter(i => !i.pull_request) : [];
const actualPRs = Array.isArray(prs) ? prs : [];

// Oldest open PR
const oldestPR = actualPRs.length > 0
  ? actualPRs.sort((a,b) => new Date(a.created_at) - new Date(b.created_at))[0]
  : null;

// PRs open > 7 days
const stalePRs = actualPRs.filter(pr => {
  const days = (Date.now() - new Date(pr.created_at)) / (1000 * 60 * 60 * 24);
  return days > 7;
});

// Top 3 oldest issues
const oldestIssues = actualIssues
  .sort((a,b) => new Date(a.created_at) - new Date(b.created_at))
  .slice(0, 3);

const today = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });

let prList = actualPRs.slice(0, 5).map(pr => `• [#${pr.number}](${pr.html_url}) ${pr.title}`).join('\n') || 'None';
let issueList = oldestIssues.map(i => `• [#${i.number}](${i.html_url}) ${i.title}`).join('\n') || 'None';

return [{
  json: {
    today,
    open_prs: actualPRs.length,
    open_issues: actualIssues.length,
    stale_prs: stalePRs.length,
    pr_list: prList,
    issue_list: issueList,
    oldest_pr_title: oldestPR ? oldestPR.title : null,
    oldest_pr_url: oldestPR ? oldestPR.html_url : null,
    oldest_pr_days: oldestPR ? Math.floor((Date.now() - new Date(oldestPR.created_at)) / (1000*60*60*24)) : 0
  }
}];

